INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Multi-site architecture$q$, $q$Run unlimited independently themed, independently permissioned sites from one installation, all drawing on a shared pool of items and media.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$REST API with JSON-LD$q$, $q$A complete, documented REST API lets developers use Omeka S as a headless repository behind a custom front end.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Linked Open Data modeling$q$, $q$Resource Templates built on Dublin Core and other RDF vocabularies let items link out to external authorities such as Wikidata.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Modules extension system$q$, $q$Add mapping, IIIF image serving, CSV import and export, OAI-PMH harvesting and more through community and core modules.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Granular user roles$q$, $q$Global Admin, Site Admin, Editor, Reviewer, Author and Researcher roles support multi-department or multi-institution governance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$External repository connectors$q$, $q$Import from or connect to Fedora, DSpace, Zotero, CSV files, and existing Omeka Classic installations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$IIIF support$q$, $q$Serve and view high-resolution cultural heritage images using the IIIF standard used by libraries and museums worldwide.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Completely free and open source with no per-seat or per-site licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$True multi-site capability lets one team manage many public collection sites from a shared backend$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Purpose-built data model for cultural heritage and digital humanities work (Dublin Core, Linked Open Data)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Full REST API enables headless or custom front-end builds$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Backed by a long-running academic nonprofit (RRCHNM / Digital Scholar) with an established track record via Omeka Classic and Zotero$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$No first-party managed hosting for Omeka S, so self-hosting or a third-party host is required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Steeper learning curve than Omeka Classic or fully hosted platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Smaller module ecosystem than large general-purpose CMSs like WordPress or Drupal$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Deep front-end customization requires PHP and templating skill$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Not designed as a long-term digital preservation system in the way Islandora or dedicated repository software is$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$What is Omeka S?$q$, $q$Omeka S is a free, open-source web publishing platform that lets one installation run multiple independently themed digital collection sites from a shared pool of items, built for museums, libraries, archives and digital humanities projects.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$How is Omeka S different from Omeka Classic?$q$, $q$Omeka Classic runs a single standalone site and uses plugins, while Omeka S supports multiple sites from one install, ships a full REST API, uses a module system instead of plugins, and models content as Linked Open Data.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Is Omeka S free?$q$, $q$Yes. Omeka S is open-source software that can be downloaded and run at no license cost, though you need your own server or hosting provider to run it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Can I host multiple sites with Omeka S?$q$, $q$Yes, that is Omeka S's defining feature: a single installation can power an unlimited number of independently themed and permissioned sites that share a common item pool.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Does Omeka S have an API?$q$, $q$Yes, Omeka S includes a full REST API that returns data in JSON-LD by default, allowing it to be used as a headless backend behind a custom-built front end.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Who maintains Omeka S?$q$, $q$Omeka S is maintained by Digital Scholar (the Corporation for Digital Scholarship), a nonprofit that also maintains Omeka Classic and Zotero, building on original development by the Roy Rosenzweig Center for History and New Media at George Mason University.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$What skills do I need to run Omeka S?$q$, $q$Basic web server administration is required to install and host Omeka S, and PHP/HTML/CSS knowledge is helpful for deeper theme or module customization, though day-to-day content entry does not require coding.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$University and library digital collections$q$, $q$Academic libraries digitize special collections and publish them as searchable, richly described online exhibits across multiple departmental sites.$q$, $q$Academic libraries and archivists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Museum online exhibits$q$, $q$Museums build public-facing exhibit sites drawing on a shared collections database, with IIIF image viewing for high-resolution artifacts.$q$, $q$Museums and cultural heritage organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Digital humanities research projects$q$, $q$Researchers structure and publish primary source material as Linked Open Data, linking items to external authorities like Wikidata for scholarly reuse.$q$, $q$Digital humanities scholars and research teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under an open-source license","Unlimited sites and items, limited only by your server","Full REST API access","Community modules and themes","Requires your own server/hosting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Omeka S is the API-first, multi-site sibling of Omeka Classic, both developed by the Roy Rosenzweig Center for History and New Media at George Mason University and today maintained by the nonprofit Digital Scholar (Corporation for Digital Scholarship). Released as a 1.0 in November 2017, Omeka S was built from the ground up for institutions that need to run several related but independently branded websites from one shared backend of items, media and metadata.$q$, $q$Unlike Omeka Classic, which is a single standalone site with a 'plugin' extension model, Omeka S uses a 'module' system, exposes a full REST API by default, and treats every item as Linked Open Data that can reference external vocabularies such as Wikidata. That makes it a reasonable choice either as a traditional exhibit-building CMS or as a headless repository powering a custom front end.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core strengths include true multi-site architecture from a single install, Resource Templates for consistent metadata built on Dublin Core and other RDF vocabularies, and a REST API returning JSON-LD, which together let developers decouple the public presentation layer from the underlying collection data if desired.$q$, $q$The module ecosystem adds mapping, IIIF-compliant image viewing for cultural heritage imagery, CSV bulk import and export, OAI-PMH harvesting, and connectors into Fedora, DSpace, and Zotero, plus tools to migrate content over from an existing Omeka Classic site.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Omeka S itself is completely free and open source under a GPL-style license; there is no subscription fee to download or run the software. Institutions do need to provide their own server (or use a third-party Omeka-friendly host) since, unlike Omeka Classic, there is no official Omeka.net managed hosting plan built specifically for Omeka S.$q$, $q$Because there is no vendor lock-in or per-user licensing, total cost of ownership is really a function of hosting, IT support, and any custom module or theme development an institution chooses to commission.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed103661-d4a3-4fa4-8ac8-dccb7c67ed04', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Unified email, SMS and web push$q$, $q$Manage all three messaging channels from one customer profile, one automation builder, and one subscription price.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Ecommerce automation workflows$q$, $q$Prebuilt sequences for cart abandonment, welcome series, browse abandonment, order updates and win-back campaigns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Native ecommerce integrations$q$, $q$Deep, direct integrations with Shopify, WooCommerce, BigCommerce and Magento pull store data straight into campaigns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Drag-and-drop email builder$q$, $q$Visual editor with ecommerce-specific content blocks such as product pickers and dynamic discount codes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Behavior-based segmentation$q$, $q$Segment audiences using purchase history, browsing behavior and campaign engagement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Popups and signup forms$q$, $q$A/B-testable popups, landing pages and signup forms to grow email and SMS lists.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Sales-attribution reporting$q$, $q$Dashboard that ties revenue directly back to individual campaigns and automations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$AI-assisted content and personalization$q$, $q$AI tools for form copy, product recommendations and dynamic content on the Pro and Custom plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Genuinely usable free plan, not just a trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Bundles email, SMS and web push under one price instead of separate per-channel billing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Deep native integrations with Shopify, WooCommerce and other major ecommerce platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Large library of prebuilt ecommerce automation workflows reduces setup time$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Usage-based SMS pricing that scales down at higher volumes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Pricing rises quickly as your contact list grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Free plan sending volumes are quite low for anything beyond a very small store$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Most advanced AI personalization and reporting features are reserved for the Pro and Custom tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$SMS deliverability and coverage are strongest in the US, Canada and UK$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Complex multi-step automations can take time to learn for marketing teams new to the platform$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Is Omnisend free?$q$, $q$Yes, Omnisend offers a Free plan covering 500 emails and 250 contacts per month with limited web push notifications; paid plans start at roughly $16 per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$What ecommerce platforms does Omnisend integrate with?$q$, $q$Omnisend has native integrations with Shopify, WooCommerce, BigCommerce and Magento, plus a broader app marketplace for other platforms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Does Omnisend support SMS marketing?$q$, $q$Yes, SMS is built into the platform and billed on a per-message basis starting around $0.007 to $0.009 per message, included as credits on the Pro plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$How is Omnisend priced?$q$, $q$Pricing is based on your number of contacts and monthly send volume across a Free plan, Standard plan (from about $16/month), Pro plan (from about $59/month) and a Custom high-volume tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$What was Omnisend called before?$q$, $q$Omnisend was originally launched in 2014 as Soundest and rebranded to Omnisend in November 2017.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Can I use Omnisend for cart abandonment emails?$q$, $q$Yes, cart abandonment is one of Omnisend's prebuilt automation workflows and one of its most commonly used features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Who is Omnisend best suited for?$q$, $q$Omnisend is best suited for small-to-midsize direct-to-consumer ecommerce brands that want combined email and SMS marketing without managing separate tools for each channel.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Cart and browse abandonment recovery$q$, $q$Automatically follow up with shoppers who added items to cart or browsed products without purchasing, using email and SMS sequences.$q$, $q$DTC ecommerce brands on Shopify or WooCommerce$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Combined email and SMS promotional campaigns$q$, $q$Run coordinated sale and product-launch campaigns across email, SMS and web push from a single audience segment.$q$, $q$Mid-market ecommerce marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Post-purchase lifecycle automation$q$, $q$Send order confirmations, shipping updates, review requests and win-back offers automatically after a purchase.$q$, $q$Online retailers focused on repeat purchase and retention$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["500 emails per month","250 contacts","500 web push notifications","Access to core features","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Standard$q$, $q$From about $16/month$q$, $q$Monthly, scales with contact count$q$, NULL, $q$["6,000 emails per month","Unlimited web push notifications","AI-assisted signup forms","No Omnisend branding","Account support from $400/month spend"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Pro$q$, $q$From about $59/month$q$, $q$Monthly, scales with contact count$q$, NULL, $q$["Unlimited emails","SMS credits included, from $0.007 per message","Advanced AI personalization","Dynamic content and product recommendations","Advanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Custom$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Tailored for high-volume senders and large contact lists","Dedicated account support","Custom onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Omnisend is a marketing automation platform focused exclusively on ecommerce, founded in 2014 in Lithuania (originally as Soundest) and rebranded to Omnisend in 2017. It is headquartered in Vilnius with additional offices in Kaunas and Charleston, South Carolina, and now serves over 150,000 online stores.$q$, $q$The platform's core proposition is unifying email, SMS and web push under a single customer profile, single automation builder and single price, so ecommerce teams do not need to stitch together separate tools for each channel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Omnisend ships with native, deep integrations for Shopify, WooCommerce, BigCommerce and Magento, letting store data such as products, orders and discount codes flow directly into campaigns. A drag-and-drop email builder includes ecommerce-specific blocks like product pickers and dynamic discount codes.$q$, $q$Prebuilt automation workflows cover cart abandonment, welcome series, browse abandonment, order and shipping confirmations, and win-back sequences, alongside behavior-based segmentation, A/B-testable popups and signup forms, and a sales-attribution reporting dashboard.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Omnisend uses a freemium, contact-count-based pricing model. The Free plan covers 500 emails and 250 contacts per month with limited web push notifications. The Standard plan starts at roughly $16 per month for 6,000 monthly emails, and the Pro plan starts at roughly $59 per month with unlimited email sends plus usage-based SMS credits.$q$, $q$SMS is billed per message on top of the Pro plan (from about $0.007 to $0.009 per message depending on volume), and a Custom/High-volume tier is available for large contact lists with dedicated account management.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Client-side, no-upload processing$q$, $q$Every conversion or edit runs locally in the browser (or your own server), so files never leave the device.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$80-plus utilities in one app$q$, $q$Image, PDF, video, text, date/time, math and data tools consolidated into a single interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Self-hostable via Docker$q$, $q$An official, lightweight roughly 28MB Docker image lets teams run OmniTools on their own infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Image and PDF editing$q$, $q$Background removal, resizing and format conversion for images; merging, splitting and annotating for PDFs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Data format converters$q$, $q$JSON, CSV and XML viewers and converters aimed at developers handling structured data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$No ads, no tracking$q$, $q$The project is positioned explicitly as an ad-free, tracking-free public utility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$MIT-licensed open source$q$, $q$Fully open codebase on GitHub that can be forked, audited or extended by the community.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Completely free with no account, subscription, or usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Strong privacy model since files are processed client-side and never uploaded$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Wide breadth of tools (80-plus) covering image, PDF, video, text and data needs in one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Easy to self-host via a small official Docker image for internal or air-gapped use$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Active open-source project with fast growth and frequent releases since its 2024 launch$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$No official company, support contract or SLA since it is a community project, not a business$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Feature velocity depends on volunteer contributions rather than a dedicated roadmap$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Lacks enterprise features like team accounts, audit logs or compliance certifications$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Client-side processing can be slower than server-side tools for very large files$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$No native mobile apps; it is a browser-based tool only$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Is OmniTools free?$q$, $q$Yes, OmniTools is completely free, open-source software with no paid tier or account requirement.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Is OmniTools safe for sensitive files?$q$, $q$OmniTools processes files entirely client-side in the browser (or on your own server if self-hosted), so files are never uploaded to a third-party cloud, which improves privacy compared with typical online converters.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Can I self-host OmniTools?$q$, $q$Yes, OmniTools provides an official lightweight Docker image (about 28MB) that can be deployed on your own server or home lab.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Who built OmniTools?$q$, $q$OmniTools was created by developer iib0011 and is maintained as an open-source project on GitHub with community contributions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$What tools does OmniTools include?$q$, $q$OmniTools includes over 80 utilities spanning image editing, PDF manipulation, video trimming, text conversion, date/time calculators, and data format converters like JSON, CSV and XML.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$How is OmniTools different from iLovePDF or TinyPNG?$q$, $q$Unlike those cloud-based services, OmniTools processes files locally in the browser or on your own server, is free and open source, and does not require uploading files to a third-party company.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Does OmniTools require an account?$q$, $q$No, OmniTools does not require creating an account to use its tools on the hosted version.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Privacy-conscious file conversion$q$, $q$Convert, resize or merge files without uploading them to a third-party cloud service.$q$, $q$Privacy-conscious individuals and regulated organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Self-hosted internal utility hub$q$, $q$Deploy OmniTools via Docker on internal infrastructure so a team has a shared, private set of file utilities.$q$, $q$Developers and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Everyday quick conversions$q$, $q$Handle one-off tasks like resizing an image, merging PDFs, or converting CSV to JSON without installing separate desktop software.$q$, $q$General consumers and knowledge workers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Hosted (omnitools.app)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["80-plus browser-based tools","Client-side processing, no uploads","No account required","No ads or tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$Self-Hosted (Docker)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Official lightweight Docker image (about 28MB)","Run on your own server or home lab","Full data control","MIT-licensed source code"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OmniTools is an open-source, self-hostable web app created by developer iib0011, with its GitHub repository dating to June 2024. It bundles more than 80 everyday utilities across image, PDF, video, text, date/time, and data-format categories into a single, ad-free interface.$q$, $q$It was built explicitly as a privacy-friendly alternative to popular proprietary services like iLovePDF and TinyPNG: rather than uploading files to a third-party server, OmniTools processes everything client-side in the browser, or on your own infrastructure if you self-host it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The toolset spans image tools (background removal, resizing, format conversion), PDF tools (merge, split, annotate), video tools (trim, convert, reverse), text and list utilities (case conversion, shuffling, formatting), date and time calculators, math and unit tools, and data utilities such as JSON, CSV and XML viewers and converters.$q$, $q$All processing happens locally, meaning no file uploads and no server-side storage of user data, and the project ships an official lightweight Docker image (about 28MB) for teams that want to self-host it internally.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OmniTools is entirely free and MIT-licensed with no paid tier, subscription, or account requirement. Users can either use the hosted version at omnitools.app at no cost or self-host the Docker image on their own server for full control.$q$, $q$Because there is no commercial product behind it, there is no enterprise support contract or SLA; support comes from the open-source community via GitHub.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea56c01c-6b17-4ccc-b7b7-0f3ee6227368', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Multi-platform saving (historical)$q$, $q$Saved content via browser extension, iOS/Android apps, or direct email forwarding into a unified reading list.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Distraction-free reader view (historical)$q$, $q$Stripped articles of ads and clutter for a clean reading experience.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Highlighting and notes (historical)$q$, $q$Users could highlight passages and attach notes to saved content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Full-text search (historical)$q$, $q$Searched across the full text of all saved articles and documents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Note-taking app integrations (historical)$q$, $q$Synced highlights and notes into Obsidian and Logseq.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Fully open-source codebase (historical)$q$, $q$The entire stack, API, and mobile clients were published on GitHub, enabling self-hosting.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Was completely free with no paid tier while operating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Fully open source, so self-hosting was possible for technical users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Clean, ad-free reading experience across web and mobile$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Strong integrations with note-taking tools like Obsidian and Logseq$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Codebase remains publicly available on GitHub as a reference or self-host base even after shutdown$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$The hosted service is permanently shut down as of November 15, 2024$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$All user data was deleted after the export window closed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$No mobile apps or browser extensions currently function for saving new content$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Self-hosting the abandoned codebase requires real technical effort with no official support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Former users must migrate to a different tool entirely, with no official import path forward from the company$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Is Omnivore still available?$q$, $q$No. Omnivore was acquired by ElevenLabs on November 1, 2024, and the hosted service was shut down on November 15, 2024, with user data deleted after an extended export window.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Why did Omnivore shut down?$q$, $q$ElevenLabs acquired Omnivore primarily to bring its engineering team on board to work on its ElevenReader app, not to continue operating the Omnivore product, so the service had no continuing owner and was discontinued.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Can I still export my Omnivore data?$q$, $q$The export window closed November 30, 2024, and all user data has since been deleted; no export is currently possible through the official service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Is Omnivore's code still available?$q$, $q$Yes, Omnivore was fully open source and its codebase remains publicly available on GitHub, so technically capable users can self-host their own instance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$What happened to the Omnivore team?$q$, $q$The Omnivore team joined ElevenLabs to work on ElevenReader, an AI-powered reading and listening application.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$What are good alternatives to Omnivore?$q$, $q$Common alternatives include Readwise Reader, Instapaper, Matter, and self-hosted open-source options like Wallabag.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$When was Omnivore founded?$q$, $q$Omnivore was founded around 2021 and was based in San Francisco before its November 2024 acquisition and shutdown.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Historical reference for read-it-later research$q$, $q$Understand Omnivore's feature set and acquisition history when comparing today's read-it-later tools.$q$, $q$Researchers and journalists covering software acquisitions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Self-hosting the open-source codebase$q$, $q$Technically capable users can deploy Omnivore's published code on their own infrastructure since the hosted service is discontinued.$q$, $q$Developers comfortable with self-hosted open-source software$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Migration planning$q$, $q$Former Omnivore users evaluating where to move their reading workflow after the shutdown.$q$, $q$Former Omnivore users choosing a replacement tool$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$Service Discontinued$q$, $q$N/A$q$, $q$N/A$q$, NULL, $q$["Hosted service shut down November 15, 2024","No new signups or syncing available","Open-source code remains on GitHub for self-hosting only"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Omnivore was a free, open-source read-it-later app founded around 2021 and based in San Francisco. It offered a clean reading experience for articles, newsletters and PDFs across web, iOS, Android and browser extensions, with highlighting, notes, full-text search and integrations into tools like Obsidian and Logseq.$q$, $q$Omnivore is no longer an operating product. ElevenLabs, the AI voice company, acquired Omnivore on November 1, 2024, primarily to bring on its engineering team, and the Omnivore service was shut down on November 15, 2024. All user data was subsequently deleted after an extended export window ending November 30, 2024.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$key-features$q$, $q$Key Features (Historical)$q$, 2, ARRAY[$q$While active, Omnivore supported saving content via browser extension, mobile app, or email forwarding, offline reading, highlighting and note-taking, full-text search across saved articles, a clean reader view stripped of ads and clutter, and newsletter subscription management.$q$, $q$It also stood out for being fully open source end to end, meaning technically capable users could self-host their own instance rather than relying solely on the hosted omnivore.app service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', $q$pricing-overview$q$, $q$Pricing (Historical)$q$, 2, ARRAY[$q$Omnivore was offered free of charge throughout its operating life, funded by venture investment rather than subscription revenue, with no meaningful paid tier for end users.$q$, $q$Since the November 2024 shutdown, there is no pricing to evaluate: the hosted service no longer accepts new users or syncs content, and the only remaining option is self-hosting the open-source codebase.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0882639c-99a4-4dc9-ad54-7de7889c2d10', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Radio-to-podcast automation$q$, $q$Automatically captures live radio broadcasts and republishes them as on-demand podcast episodes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Drag-and-drop audio editing$q$, $q$Built-in editing tools for trimming, splicing and preparing episodes for publication.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Embeddable, customizable players$q$, $q$Shareable audio players that can be embedded on websites and branded to match a network's identity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Dynamic ad insertion$q$, $q$Monetization tools connected to Triton Digital's advertising marketplace for programmatic and dynamic ads.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Enterprise analytics$q$, $q$Detailed audience measurement and reporting built for advertiser and ratings use cases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Multi-directory distribution$q$, $q$Publishes episodes out to major podcast directories and platforms from a single dashboard.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Purpose-built for radio broadcasters repurposing linear content into podcasts$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Backed by Triton Digital's broader digital audio advertising and measurement ecosystem$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Strong monetization tooling via dynamic ad insertion$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Enterprise-grade analytics suited for advertiser and ratings reporting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Long operating history since its 2015 platform launch and 2019 acquisition by an established audio company$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$No public self-serve pricing; requires a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Not designed or priced for independent or small-scale podcasters$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Feature set and pricing are tightly coupled to Triton Digital's broader advertising ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Less suited to creators who just need simple, low-cost RSS hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Onboarding and setup are geared toward enterprise procurement rather than instant self-signup$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$What is Omny Studio?$q$, $q$Omny Studio is an enterprise podcast hosting and audio-on-demand platform, originally built in Melbourne, Australia and now owned by Triton Digital, a subsidiary of The E.W. Scripps Company.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Who owns Omny Studio?$q$, $q$Omny Studio is owned by Triton Digital, which acquired the company on June 12, 2019 after a strategic partnership that began in 2017; Triton Digital is itself a subsidiary of The E.W. Scripps Company.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$How much does Omny Studio cost?$q$, $q$Omny Studio does not publish pricing; it is sold through an enterprise sales process, so you need to contact the company directly for a quote.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Is Omny Studio good for independent podcasters?$q$, $q$Omny Studio is primarily built for radio broadcasters, publishers and large branded podcast networks rather than independent or small podcasters, who are typically better served by lighter-weight hosts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Does Omny Studio support radio broadcast capture?$q$, $q$Yes, one of its signature features is automatically capturing live radio broadcasts and republishing them as on-demand podcast episodes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Does Omny Studio offer ad monetization?$q$, $q$Yes, it includes dynamic ad insertion tools connected to Triton Digital's advertising marketplace.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$When was Omny Studio founded?$q$, $q$The company behind Omny Studio was founded in 2012 in Melbourne, Australia, and the Omny Studio platform itself launched in 2015.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Repurposing radio broadcasts as podcasts$q$, $q$Radio stations automatically capture live broadcasts and republish them as on-demand podcast episodes to reach digital audiences.$q$, $q$Radio broadcasters and radio groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Branded media network podcast operations$q$, $q$Large publishers and media companies manage many shows across a single enterprise hosting and analytics platform.$q$, $q$Media companies and branded podcast networks$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Advertiser-driven podcast monetization$q$, $q$Networks use dynamic ad insertion and detailed audience analytics to sell and report on podcast advertising at scale.$q$, $q$Enterprise advertising and sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$Enterprise (Custom)$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Radio-to-podcast automation","Dynamic ad insertion and monetization","Enterprise analytics and reporting","Dedicated account management","Contact sales for a quote"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Omny Studio began life in Melbourne, Australia in 2012 as 121cast, initially focused on text-to-speech technology, before pivoting toward personalized audio and launching the Omny Studio platform in 2015. After a strategic partnership starting in 2017, Triton Digital, a global digital audio technology company and subsidiary of The E.W. Scripps Company, fully acquired Omny Studio in June 2019.$q$, $q$Today Omny Studio operates as Triton Digital's enterprise podcast hosting and audio-on-demand platform, aimed squarely at radio broadcasters, media companies and large branded podcast networks rather than independent creators.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Omny Studio can automatically capture live radio broadcasts and republish them as on-demand podcast episodes, alongside drag-and-drop audio editing tools, customizable embeddable players, and distribution to major podcast directories.$q$, $q$Its enterprise focus shows in built-in dynamic ad insertion and monetization tools connected to Triton's advertising marketplace, plus detailed analytics and audience measurement designed for advertiser reporting and ratings purposes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60043245-a189-4894-95be-8b1ffc4e271a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Omny Studio does not publish self-serve pricing; it is sold through a sales-led enterprise process aimed at radio broadcasters, publishers and large branded podcast networks.$q$, $q$Prospective customers need to contact Triton Digital directly to get a quote, and pricing typically reflects broadcast volume, ad monetization needs and integration with Triton's broader audio advertising ecosystem.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$WYSIWYG booking page designer$q$, $q$Build and customize branded booking pages without code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Calendar and video integrations$q$, $q$Connects with Google, Microsoft 365, Exchange and iCloud calendars, and Zoom, Google Meet, Microsoft Teams and Webex for video meetings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Lead routing and distribution$q$, $q$Round-robin and rules-based logic assigns inbound meeting requests to the right sales rep automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Multi-host and group meetings$q$, $q$Supports meetings involving multiple hosts or group sessions, not just one-on-one bookings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$AI-powered chatbots$q$, $q$Embeddable chatbots handle natural-language conversations and hand visitors off to a live meeting instantly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$CRM integrations$q$, $q$Native integrations with Salesforce and HubSpot sync meeting and lead data automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Stripe payment collection$q$, $q$Collect payment at the time of booking via built-in Stripe integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Security and compliance add-on$q$, $q$Optional SSO and HIPAA business associate agreement support for regulated industries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Covers the full meeting journey, from booking through lead routing to CRM sync, not just calendar links$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Free plan available for individual users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Strong fit for B2B sales teams that need inbound lead distribution logic$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Deep CRM integrations with Salesforce and HubSpot$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Dedicated Enterprise tier with security and legal review support for larger organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$More complex to set up than simple scheduling tools if you only need a basic booking link$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Advanced routing and AI chatbot features are locked behind higher-priced tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Per-seat pricing can add up quickly for larger sales teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Security and compliance features like SSO require an additional paid add-on$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Headquarters and company details are inconsistently reported across sources, reflecting a distributed multi-office structure$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$What was OnceHub called before?$q$, $q$OnceHub was originally launched as ScheduleOnce in 2006 and rebranded to OnceHub in 2022 to reflect a broader focus on the full prospect-to-meeting pipeline.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Is OnceHub free?$q$, $q$Yes, OnceHub offers a free Basic plan for one user with one connected calendar and one booking page; paid plans start at $10 per seat per month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Does OnceHub support lead routing?$q$, $q$Yes, the Route plan and above include rules-based and round-robin distribution logic to route inbound meeting requests to the right team member.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Does OnceHub integrate with Salesforce and HubSpot?$q$, $q$Yes, CRM integrations with Salesforce and HubSpot are available starting on the Schedule plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Does OnceHub offer AI chatbots?$q$, $q$Yes, the Engage plan includes AI-powered chatbots that can hand a website visitor directly into a live meeting.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$How much does OnceHub cost for larger teams?$q$, $q$Team plans range from $10 to $39 per seat per month billed annually, and organizations with 30 or more seats can get custom Enterprise pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Who is OnceHub best suited for?$q$, $q$OnceHub is best suited for B2B sales, financial services and professional services teams that need scheduling combined with lead routing and CRM integration, rather than solo users who just need a personal booking link.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Inbound sales lead qualification and routing$q$, $q$Route inbound demo requests to the correct sales rep automatically using round-robin or rules-based logic.$q$, $q$B2B sales development and revenue operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Client meeting scheduling for regulated industries$q$, $q$Financial services and professional services firms schedule client meetings with SSO and HIPAA compliance support.$q$, $q$Financial services and professional services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Website chatbot to instant meeting handoff$q$, $q$Convert website visitors into booked meetings in real time via an embedded AI chatbot.$q$, $q$Marketing and sales teams running high-intent websites$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 user, 1 connected calendar, 1 booking page","WYSIWYG booking page designer","Calendar and video integrations","Standard email and calendar notifications"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Schedule$q$, $q$$10/seat/month billed annually ($12 month-to-month)$q$, $q$Annual or monthly$q$, NULL, $q$["Unlimited booking links and meetings","One dedicated phone number included","Multi-host and group meetings","Salesforce and HubSpot CRM integrations","Stripe payment integration","24/7 email and live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Route$q$, $q$$19/seat/month billed annually ($23 month-to-month)$q$, $q$Annual or monthly$q$, NULL, $q$["All Schedule features","Two phone numbers included","Unlimited routing forms","Dynamic meeting distribution","Room scheduling with directory integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Engage$q$, $q$$39/seat/month billed annually ($47 month-to-month)$q$, $q$Annual or monthly$q$, NULL, $q$["All Route features","Three phone numbers included","AI-powered chatbots","Live chat and instant meeting handoff","Audience-specific targeting"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom (30+ seats)$q$, NULL, $q$["All Engage features","Dedicated success manager","Security and legal reviews","VIP support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OnceHub was founded in 2006 by brothers Gilad and Rami Goraly under the name ScheduleOnce and rebranded to OnceHub in 2022 to reflect a broader mission covering the full prospect-to-meeting pipeline, not just calendar booking. It is incorporated in Claymont, Delaware with roughly 200 employees across offices in Israel, the UK, South Africa, India, Ireland, Colombia and the US.$q$, $q$The platform now serves over 15,000 businesses, with a heavy concentration in B2B sales, financial services and professional services teams that need more than a simple personal booking link.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OnceHub covers the full meeting journey: WYSIWYG booking pages, calendar integrations (Google, Microsoft 365, Exchange, iCloud), and video integrations (Zoom, Google Meet, Microsoft Teams, Webex), plus inbound lead routing with round-robin or rules-based distribution across sales teams and multi-host or group meeting booking.$q$, $q$Higher tiers add embeddable, AI-driven chatbots that hand a website visitor straight into a live meeting, CRM integrations with Salesforce and HubSpot, and Stripe-based payment collection at the time a meeting is booked.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bde29d40-4c62-40a8-861e-ba3a8862dedc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OnceHub uses a freemium, per-seat pricing model. Basic is free for a single user; Schedule starts at $10 per seat per month billed annually; Route starts at $19 per seat per month annually and adds lead-routing logic; Engage starts at $39 per seat per month annually and adds AI chatbots.$q$, $q$An Enterprise tier with custom pricing is available for organizations with 30-plus seats, and a separate Security and Compliance add-on (from $5/seat/month annually) provides SSO and HIPAA business associate agreements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Log file analysis at scale$q$, $q$Analyzes real server log files to show exactly how search engine crawlers behave on a site.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Crawl budget and orphan page detection$q$, $q$Identifies wasted crawl budget and pages that receive no internal links or crawler attention.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$JavaScript rendering$q$, $q$Crawls and renders JavaScript-heavy pages to analyze SEO issues invisible to a standard crawler.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$SQL-like Data Explorer$q$, $q$Lets technical SEO teams build custom, cross-referenced reports combining crawl, log and ranking data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Structured data monitoring$q$, $q$Tracks structured data implementation and errors across large sites.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Crawl-over-crawl comparison$q$, $q$Compares crawls over time to catch technical SEO regressions before they hurt rankings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Search Console and Analytics integration$q$, $q$Pulls in Google Search Console and Google Analytics data to correlate technical issues with organic performance.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Genuinely deep log file analysis built for very large, complex websites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Flexible custom reporting via a SQL-like Data Explorer$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Strong JavaScript rendering support for modern, JS-heavy sites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Backed by BrightEdge's broader enterprise SEO resources since the 2022 acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Established track record since 2013 with enterprise ecommerce and publisher clients$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$No public self-serve pricing; requires a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Overkill and cost-prohibitive for small to mid-sized websites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Steeper learning curve than lighter desktop crawlers like Screaming Frog$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Increasingly positioned as part of the broader BrightEdge suite rather than a fully independent product$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Log file analysis requires access to and comfort working with raw server logs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Is Oncrawl still an independent company?$q$, $q$No, Oncrawl was acquired by BrightEdge in February 2022 and now operates as part of BrightEdge's product portfolio, though it continues under its own brand name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$How much does Oncrawl cost?$q$, $q$Oncrawl does not publish self-serve pricing; you need to contact sales or book a demo to get a quote, and pricing typically scales with crawl and log file volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$What is Oncrawl best used for?$q$, $q$Oncrawl is best used for technical SEO crawling and log file analysis on very large, complex websites such as ecommerce catalogs, marketplaces and large publishers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Does Oncrawl analyze server log files?$q$, $q$Yes, log file analysis is one of Oncrawl's core capabilities, showing exactly how search engine crawlers behave on a site.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Who founded Oncrawl?$q$, $q$Oncrawl was founded in 2013 in Bordeaux, France by François Goube and Tanguy Moal.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Does Oncrawl support JavaScript SEO analysis?$q$, $q$Yes, Oncrawl can crawl and render JavaScript-heavy pages to surface SEO issues that a standard HTML-only crawler would miss.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$What are alternatives to Oncrawl?$q$, $q$Common alternatives include Screaming Frog, Botify, Lumar (formerly Deepcrawl), Sitebulb and ContentKing.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Enterprise ecommerce technical SEO audits$q$, $q$Analyze crawl behavior and log files across large product catalogs to fix crawl budget waste and indexing issues.$q$, $q$Enterprise ecommerce and marketplace SEO teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Publisher crawl efficiency monitoring$q$, $q$Track how search engines crawl and index a high-volume publishing site over time.$q$, $q$Large media and publisher SEO teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Agency technical SEO consulting$q$, $q$Agencies use Oncrawl's log analysis and custom reporting to diagnose technical issues for large enterprise clients.$q$, $q$Technical SEO consultants and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$Enterprise (Custom)$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Large-scale crawling and log file analysis","JavaScript rendering","Custom Data Explorer reporting","Structured data monitoring","Contact sales for a quote"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Oncrawl was founded in 2013 in Bordeaux, France by François Goube and Tanguy Moal to build a more powerful, accessible technical SEO crawler for large and complex websites. It raised several million dollars from French investors before being acquired by BrightEdge, a major enterprise SEO platform, in February 2022.$q$, $q$Since the acquisition, Oncrawl has continued operating under its own brand as BrightEdge's dedicated technical crawling and log file analysis product, aimed at enterprise SEO teams managing very large sites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Oncrawl combines crawl data with real server log files to show exactly how search engine crawlers behave on a site, including crawl frequency, crawl budget waste and orphan pages, and correlates that behavior with organic traffic and rankings.$q$, $q$It also offers JavaScript rendering for SEO analysis of JS-heavy sites, a SQL-like Data Explorer for building custom cross-referenced reports, structured data monitoring, crawl-over-crawl comparison, and integrations with Google Search Console and Google Analytics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb746904-348f-44b6-aca5-49626cad1b9a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Oncrawl no longer publishes self-serve pricing since becoming part of BrightEdge in 2022; access is arranged through a sales and demo process rather than an online checkout.$q$, $q$Pricing is generally understood to scale with crawl volume, log file data volume and the broader scope of an organization's BrightEdge relationship, positioning it firmly as an enterprise-tier purchase.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Self-destructing one-time links$q$, $q$A secret is permanently deleted from all storage the moment it is viewed once, so the link can never be reopened.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Configurable expiration$q$, $q$Set secrets to expire automatically after minutes up to 14 days on the free plan, or up to 30 days on the paid plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Custom domains$q$, $q$Share secrets from your own branded domain instead of the default onetimesecret.com link.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$REST API$q$, $q$Programmatically create and manage secrets for integration into internal tools and workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Open-source, self-hostable codebase$q$, $q$The full codebase is published on GitHub and can be self-hosted via Docker for complete data control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Custom branding$q$, $q$Add your own logo and branding to the secret-sharing experience on the Identity Plus plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Team member invitations$q$, $q$Invite unlimited team members to a shared account on the Identity Plus plan.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Free plan is fully functional, including a custom domain and REST API access$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Open source with the option to self-host for full data control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Over a decade of continuous operating history since 2011$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Simple, no-friction experience: no account required to view a shared secret$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Straightforward, transparent paid tier at a flat monthly price$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Encryption is server-side, not fully zero-knowledge, so the operator's server briefly handles plaintext$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Free plan expiration is capped at 14 days$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Custom branding and unlimited domains require the paid Identity Plus tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Built for short text secrets, not designed for sharing large files$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$No native mobile apps; it is a web-based tool only$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$What is One Time Secret used for?$q$, $q$One Time Secret is used to share sensitive text like passwords, API keys and credentials via a link that self-destructs after being viewed once, so the information never sits permanently in email or chat history.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Is One Time Secret free?$q$, $q$Yes, the Basic plan is free and includes one custom domain, expiration up to 14 days, and REST API access; a paid Identity Plus plan at 35 euros per month adds unlimited domains and custom branding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$What happens after a secret is viewed?$q$, $q$Once a secret link is opened, it is permanently deleted from all storage and can never be viewed again, even by the original sender.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Is One Time Secret open source?$q$, $q$Yes, the full codebase is open source and published on GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Can I self-host One Time Secret?$q$, $q$Yes, because it is open source, technically capable users can self-host their own instance, typically via Docker, instead of using the hosted onetimesecret.com service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Does One Time Secret use end-to-end encryption?$q$, $q$Not fully. Each secret is encrypted with its own unique key before being stored, but encryption happens server-side, meaning the operator's server briefly handles the plaintext rather than using fully zero-knowledge client-side encryption.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$How long can a secret stay active before it expires?$q$, $q$Expiration is configurable up to 14 days on the free Basic plan and up to 30 days on the paid Identity Plus plan.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Sharing credentials with teammates or IT support$q$, $q$Send passwords or access credentials internally without leaving them in permanent chat or email history.$q$, $q$IT and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Sending API keys or database passwords to clients$q$, $q$Developers and agencies share one-off credentials with clients or contractors via a link that disappears after use.$q$, $q$Developers and digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$One-off sharing of sensitive personal information$q$, $q$Individuals send private information such as account numbers or personal details securely to another person.$q$, $q$General consumers and individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Basic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["One custom domain","Automatic destruction after viewing","Expiration configurable up to 14 days","Email links to recipients","REST API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$Identity Plus$q$, $q$35 EUR/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Basic","Unlimited custom domains","Custom branding with your own logo","Expiration up to 30 days","Unlimited member invitations","Homepage access controls"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$One Time Secret has been running since 2011 as a simple, focused tool for sharing sensitive text, such as passwords or API keys, via a link that self-destructs after a single view. It started as a small hobby project and has grown into a sustainable small business with paid plans, custom domains and multi-region hosting.$q$, $q$The service is open source, with its full codebase published on GitHub, so security-conscious teams can either use the hosted onetimesecret.com service or self-host their own instance via Docker for complete control over their data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every secret is encrypted with its own unique key before storage and is permanently deleted from all storage the moment it is viewed once, so a link can never be reopened by anyone, including the original sender. Expiration can be configured from minutes up to 14 days on the free plan or 30 days on the paid plan.$q$, $q$The service supports custom domains for branded secret-sharing links, a REST API for programmatic integration into internal tools, and, on the paid tier, custom branding and unlimited team member invitations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$One Time Secret offers a fully functional free Basic plan, including one custom domain, expiration up to 14 days and REST API access, at no cost.$q$, $q$The paid Identity Plus plan costs 35 euros per month and adds unlimited custom domains, custom branding, expiration up to 30 days and unlimited member invitations; discounted rates are available for students and non-profits on request.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1d593e07-ef39-4892-8798-7b56252691bd', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
