-- Enrichment marathon batch: Omeka S, Omnisend, OmniTools, Omnivore, Omny Studio, OnceHub, Oncrawl, One Time Secret

-- ── Omeka S ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Omeka S is a free, open-source web publishing platform that lets one installation power multiple independently themed digital collection sites sharing a common item pool, purpose-built for museums, libraries, archives and digital humanities projects.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Small nonprofit team (Digital Scholar / Corporation for Digital Scholarship)$q$, company_size),
  headquarters = COALESCE($q$Vienna, Virginia, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Omeka S Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Omeka S review 2026: an open-source, multi-site, API-first platform for museums, archives and digital humanities. See features, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Omeka S is a free, open-source content management platform for building and publishing digital collections, exhibits and repositories, released as version 1.0 in November 2017 by the Roy Rosenzweig Center for History and New Media (RRCHNM) at George Mason University and maintained today by the nonprofit Corporation for Digital Scholarship (branded Digital Scholar), the same organization behind Omeka Classic and Zotero. Omeka S is architecturally distinct from its older sibling Omeka Classic: a single Omeka S installation can host and administer an unlimited number of independently themed, independently permissioned sites that all draw from one shared pool of items and media, which makes it well suited to consortia, multi-department universities, and networks of small archives that want centralized management with distinct public-facing sites. It ships with a full REST API returning JSON-LD by default, so institutions can run Omeka S purely as a headless data repository behind a custom-built front end. Content modeling is based on Linked Open Data principles: Resource Templates let curators compose item metadata from Dublin Core and other RDF vocabularies, and items can link out to external authorities such as Wikidata. Extensibility comes through Modules (Omeka S's equivalent of Omeka Classic's Plugins), covering mapping, IIIF image serving, CSV import/export, and connectors to repositories like Fedora, DSpace, and Zotero, plus a migration path from Omeka Classic. Granular roles (Global Admin, Site Admin, Editor, Reviewer, Author, Researcher) support multi-institution and multi-department governance. There is no cost to license or run Omeka S: it is free, open-source PHP software distributed for self-hosting on a standard LAMP-type server, and unlike Omeka Classic there is no first-party Omeka.net managed hosting tier specifically for Omeka S, so technical setup or a third-party hosting partner is required. This makes it strongest for institutions with in-house or contracted web/IT capacity rather than solo hobbyists wanting a point-and-click hosted site. Target users are academic libraries, museums, archives, historical societies and digital humanities researchers who need a public exhibit or repository site backed by structured, linkable metadata. Its closest competitors are CollectiveAccess (a deeper collections-management system better suited to complex archival description and provenance), Islandora (a Drupal plus Fedora repository framework aimed at long-term preservation), ContentDM, PastPerfect, and generic CMSs like WordPress or Drupal retrofitted with archive plugins. Omeka S differentiates itself by prioritizing public access, exhibition, and interpretation of digital collections over deep preservation workflows, while still exposing enough structure and API surface to support serious scholarly and institutional use.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ed103661-d4a3-4fa4-8ac8-dccb7c67ed04';

