-- ── Omnivore ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Omnivore was a free, open-source read-it-later app for saving and reading articles, newsletters and PDFs across web, iOS, Android and browser extensions; it was acquired by ElevenLabs on November 1, 2024 and the service was shut down two weeks later on November 15, 2024.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (service discontinued November 15, 2024)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Discontinued; team joined ElevenLabs in 2024$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (prior to shutdown)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Omnivore Review 2026: Why It Shut Down and the Best Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Omnivore was acquired by ElevenLabs and shut down in November 2024. See what it offered, why it closed, and the best read-it-later alternatives in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Omnivore was a free, open-source read-it-later application founded around 2021 and headquartered in San Francisco, built as a fully open alternative to Pocket, Instapaper and Readwise Reader. It let users save articles, newsletters, PDFs and web pages from a browser extension, mobile apps (iOS and Android), or direct email forwarding, then read them in a clean, distraction-free interface with highlighting, note-taking, full-text search, and integrations into note-taking tools like Obsidian and Logseq. As a genuinely open-source project, every layer of the stack, including the API server, mobile clients and self-hosting instructions, was published on GitHub, and the product was offered entirely free with no meaningful paid tier, funded instead through venture investment. On November 1, 2024, Omnivore announced it had been acquired by ElevenLabs, the AI voice and audio company backed by Andreessen Horowitz; critically, ElevenLabs acquired Omnivore's team rather than continuing to operate its product, and the Omnivore service itself was shut down on November 15, 2024, with all user data subsequently deleted after an extended export window (initially 14 days, later extended to November 30, 2024, following user criticism about the short notice). The Omnivore engineering team joined ElevenLabs to work on ElevenReader, an AI-powered reading and listening app, rather than continuing to maintain Omnivore. As of 2026, Omnivore is not an active, usable product: its hosted service, mobile apps and browser extensions no longer function for saving or syncing content, though its open-source codebase remains publicly archived on GitHub and can theoretically be self-hosted by technically capable users, since it was fully open source under its original license. For anyone evaluating tools today, Omnivore should be understood as a defunct, historical product rather than a live SaaS option; former users have migrated to alternatives such as Readwise Reader, Instapaper, Matter, Pocket (before its own later shutdown), or self-hosted options like Wallabag. This acquisition-then-shutdown pattern, an AI company acquiring a team and discontinuing the underlying open-source product, is a notable case study in the read-it-later and bookmarking software category and is the single most important fact anyone researching Omnivore needs to know.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0882639c-99a4-4dc9-ad54-7de7889c2d10';

