-- ── OnceHub ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OnceHub (formerly ScheduleOnce) is an online scheduling and meeting-lifecycle platform used by B2B sales, financial services and professional services teams to book meetings, route leads to the right rep, and automate the prospect-to-meeting pipeline.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $10/seat/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$About 200 employees$q$, company_size),
  headquarters = COALESCE($q$Claymont, Delaware, United States (with offices including Tel Aviv, Israel)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OnceHub Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OnceHub review 2026: scheduling and meeting-routing software for B2B sales teams. Compare features, pricing plans and alternatives like Calendly and Chili Piper.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OnceHub is an online scheduling and meeting-lifecycle platform, originally launched as ScheduleOnce and founded in 2006 by brothers Gilad and Rami Goraly; the company rebranded from ScheduleOnce to OnceHub in 2022 to reflect a broader focus on the entire prospect-to-meeting pipeline rather than just calendar booking. The company is incorporated in Claymont, Delaware and operates with roughly 200 employees across offices including Israel, the United Kingdom, South Africa, India, Ireland, Colombia and the United States, serving more than 15,000 businesses, primarily in B2B sales, financial services and professional services. OnceHub's key differentiator versus simpler scheduling tools like Calendly is that it covers the full meeting journey: booking pages with a WYSIWYG designer, calendar and video integrations (Google, Microsoft 365, Exchange, iCloud, Zoom, Google Meet, Microsoft Teams, Webex), inbound lead routing and distribution logic (round-robin and rules-based assignment across sales teams), multi-host and group meeting scheduling, embeddable chatbots for instant meeting handoff from a website visitor, CRM integrations with Salesforce and HubSpot, and Stripe-based payment collection at booking time. The product line consists of two core products, ScheduleOnce (booking) and InviteOnce, and pricing is structured as a freemium, per-seat model: a Basic plan is free for one user with one connected calendar and one booking page; Schedule starts at $10 per seat per month billed annually ($12 month-to-month) and adds unlimited booking links, multi-host meetings and CRM integrations; Route starts at $19 per seat per month annually and adds lead-routing forms and dynamic meeting distribution; Engage starts at $39 per seat per month annually and adds AI-powered chatbots and live chat handoff; and an Enterprise tier offers custom pricing for organizations with 30 or more seats, including a dedicated success manager and security/legal reviews. A separate Security and Compliance add-on (from $5/seat/month annually) provides SSO and HIPAA business associate agreements. OnceHub competes most directly with Calendly, Chili Piper, HubSpot Meetings and Acuity Scheduling, and it differentiates itself by targeting revenue teams that need lead qualification and routing logic layered on top of scheduling, not just a simple personal booking link, making it a stronger fit for sales development and inbound-lead-heavy organizations than for solo professionals who just need a booking page.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bde29d40-4c62-40a8-861e-ba3a8862dedc';

