-- ── Oncrawl ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Oncrawl is a technical SEO platform for enterprise-scale website crawling and log file analysis, founded in Bordeaux, France in 2013 and acquired by BrightEdge in 2022, now operating as BrightEdge's dedicated technical SEO product line.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Operates as part of BrightEdge (large enterprise SEO company)$q$, company_size),
  headquarters = COALESCE($q$Bordeaux (Mérignac), France; now operates as part of BrightEdge$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Oncrawl Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Oncrawl review 2026: enterprise technical SEO crawling and log file analysis, now part of BrightEdge. Features, pricing model, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Oncrawl is a technical SEO platform specializing in large-scale website crawling and server log file analysis, founded in 2013 in Bordeaux (Mérignac), France by François Goube and Tanguy Moal. The company raised roughly $4.1 to $4.76 million in funding through 2018 from French investors including AQUITI Gestion and IRDI-ICSO, before being acquired by BrightEdge, a major US-based enterprise SEO platform, in February 2022; since the acquisition Oncrawl has operated as part of BrightEdge's product portfolio, positioned as BrightEdge's dedicated deep technical crawling and log analysis solution while BrightEdge's core platform handles broader enterprise SEO reporting and rank tracking. Oncrawl's key differentiator is its focus on very large, complex websites, typically ecommerce catalogs, marketplaces, publishers and other sites with hundreds of thousands to millions of URLs, where it combines crawl data with actual server log files to show exactly how Googlebot and other crawlers behave on a site, which pages get crawled and how often, crawl budget waste, orphan pages, and how crawl behavior correlates with organic traffic and rankings. Additional capabilities include JavaScript rendering for SEO analysis of JS-heavy sites, a SQL-like Data Explorer for building custom cross-referenced reports, structured data monitoring, crawl-over-crawl comparison to track technical regressions over time, and integrations with Google Search Console and Google Analytics. Since becoming part of BrightEdge, Oncrawl no longer publishes self-serve pricing; access is arranged through a sales/demo process and pricing is understood to reflect crawl volume, log file data volume and the scope of the wider BrightEdge relationship, making it firmly an enterprise-tier tool rather than a self-serve SaaS product. Its target customers are enterprise SEO teams, technical SEO consultants and agencies working with large, complex sites, and it competes most directly with other technical/enterprise crawlers such as Screaming Frog (desktop, much lower cost, less scale), Botify, Lumar (formerly Deepcrawl), Sitebulb and ContentKing. Oncrawl's main advantage is genuinely deep log file analysis at scale combined with flexible custom reporting; its main drawback for smaller teams is the lack of published pricing and self-serve signup, plus increasing integration with the broader BrightEdge suite rather than functioning as a fully independent standalone product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bb746904-348f-44b6-aca5-49626cad1b9a';

