-- ── One Time Secret ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$One Time Secret (Onetime Secret) is an open-source tool for sharing passwords, API keys and other sensitive text via a link that self-destructs after being viewed once, running since 2011 with a free tier and a paid Identity Plus tier for custom domains and branding.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Small, independently run team$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed/remote team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$One Time Secret Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$One Time Secret review 2026: share passwords and secrets via self-destructing links. Features, free vs Identity Plus pricing, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$One Time Secret, also known as Onetime Secret, is an open-source web tool for securely sharing sensitive text, such as passwords, API keys, credentials and other one-off confidential information, via a link that permanently self-destructs after it is viewed a single time. The service has been running since 2011, started by a creator known as Delano, and has grown from what its own about page describes as a long-running hobby project into a sustainable small business offering subscription plans, custom domains and multi-region hosting across the US, Canada and New Zealand (Aotearoa). Its core mechanism is simple and widely imitated: a user pastes a secret, the service generates a unique one-time link, and once that link is opened the secret is permanently deleted from all storage, so it can never be viewed a second time even by the sender; the codebase is open source and published on GitHub, letting security-conscious teams self-host their own instance via Docker instead of relying on the hosted onetimesecret.com service. One important technical nuance is that encryption happens server-side: each secret is encrypted with its own unique key before being stored and the decryption key lives on the application server rather than in the database, which is a meaningfully different trust model than fully zero-knowledge, client-side-encrypted competitors like PrivateBin, since the operator's server briefly handles the plaintext. Pricing is freemium: the free Basic plan includes one custom domain, configurable expiration up to 14 days, automatic destruction after viewing, and REST API access for programmatic secret creation, all at no cost; the paid Identity Plus plan, priced at 35 euros per month, adds unlimited custom domains, custom branding with your own logo, expiration extended up to 30 days, unlimited team member invitations, and homepage access controls, and the company also offers discounted rates for students and non-profit organizations on request. One Time Secret's target users are IT and DevOps teams sharing credentials internally, developers and agencies sending API keys or database passwords to clients or contractors, and everyday individuals who want to avoid leaving sensitive information sitting permanently in email or chat history. Its closest competitors include PrivateBin (self-hosted, zero-knowledge encrypted pastes), Yopass, Password Pusher, and newer entrants like 1time.io; One Time Secret differentiates itself through over a decade of operating history, a fully functional free tier including API access and a custom domain, and the option to either use the hosted service or self-host the open-source code for full data control.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1d593e07-ef39-4892-8798-7b56252691bd';

